import { useState, useEffect, useCallback } from 'react';

// Pattern: encapsulate complex state logic
function useToggle(initial: boolean = false) {
  const [value, setValue] = useState(initial);
  const toggle = useCallback(() => setValue((v) => !v), []);
  const setTrue = useCallback(() => setValue(true), []);
  const setFalse = useCallback(() => setValue(false), []);
  return { value, toggle, setTrue, setFalse };
}

// Pattern: window event listener
function useWindowSize() {
  const [size, setSize] = useState({ width: 0, height: 0 });

  useEffect(() => {
    function handleResize() {
      setSize({ width: window.innerWidth, height: window.innerHeight });
    }

    handleResize(); // Set initial size
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return size;
}

// Pattern: media query hook
function useMediaQuery(query: string): boolean {
  const [matches, setMatches] = useState(false);

  useEffect(() => {
    const mediaQuery = window.matchMedia(query);
    setMatches(mediaQuery.matches);

    function handler(event: MediaQueryListEvent) {
      setMatches(event.matches);
    }

    mediaQuery.addEventListener('change', handler);
    return () => mediaQuery.removeEventListener('change', handler);
  }, [query]);

  return matches;
}

// Usage: compose hooks together in components
function ResponsiveLayout() {
  const isMobile = useMediaQuery('(max-width: 768px)');
  const { width, height } = useWindowSize();
  const sidebar = useToggle(true);

  return (
    <div>
      <button onClick={sidebar.toggle}>
        {sidebar.value ? 'Hide' : 'Show'} Sidebar
      </button>
      <p>Window: {width} x {height}</p>
      {isMobile ? <MobileLayout /> : <DesktopLayout showSidebar={sidebar.value} />}
    </div>
  );
}
